export interface Question {
  id: string;
  question: string;
  options: string[];
  correctAnswer: number;
  explanation: string;
  category: string;
  difficulty: 'Easy' | 'Medium' | 'Hard';
}

export interface TestResult {
  score: number;
  totalQuestions: number;
  timeSpent: number; // in seconds
  answers: Record<string, number>;
  timestamp: number;
  anomalies: number; // For "auto-detection" focus loss
  categoryBreakdown: Record<string, { correct: number; total: number }>;
}

export enum AppState {
  IDLE = 'IDLE',
  UPLOADING = 'UPLOADING',
  GENERATING = 'GENERATING',
  TESTING = 'TESTING',
  COMPLETED = 'COMPLETED'
}

export interface TestConfig {
  title: string;
  duration: number; // in minutes
  questionCount: number;
}

import { GoogleGenAI, Type } from "@google/genai";
import { Question } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function generateMockTestFromContent(
  pdfBase64: string,
  questionCount: number = 10
): Promise<Question[]> {
  const modelName = 'gemini-3-flash-preview';

  const systemInstruction = `You are a professional examiner. Analyze the provided PDF content and generate a comprehensive mock test. 
  Each question should have 4 options. Categorize questions by topic. 
  Ensure a mix of difficulty levels. Use clear language.`;

  const responseSchema = {
    type: Type.ARRAY,
    items: {
      type: Type.OBJECT,
      properties: {
        id: { type: Type.STRING },
        question: { type: Type.STRING },
        options: { 
          type: Type.ARRAY, 
          items: { type: Type.STRING },
          minItems: 4,
          maxItems: 4
        },
        correctAnswer: { 
          type: Type.INTEGER, 
          description: "Index of the correct answer (0-3)" 
        },
        explanation: { type: Type.STRING },
        category: { type: Type.STRING },
        difficulty: { 
          type: Type.STRING,
          enum: ["Easy", "Medium", "Hard"]
        }
      },
      required: ["id", "question", "options", "correctAnswer", "explanation", "category", "difficulty"]
    }
  };

  try {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: [
        {
          parts: [
            {
              inlineData: {
                mimeType: "application/pdf",
                data: pdfBase64
              }
            },
            {
              text: `Generate ${questionCount} multiple-choice questions based on this document. Return the response strictly as a JSON array.`
            }
          ]
        }
      ],
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text) as Question[];
  } catch (error) {
    console.error("Gemini Generation Error:", error);
    throw error;
  }
}

