import React, { useState } from 'react';

interface FileUploadProps {
  onFileSelect: (base64: string, fileName: string) => void;
  isLoading: boolean;
}

export const FileUpload: React.FC<FileUploadProps> = ({ onFileSelect, isLoading }) => {
  const [isDragging, setIsDragging] = useState(false);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && file.type === 'application/pdf') {
      processFile(file);
    } else {
      alert("Please upload a valid PDF file.");
    }
  };

  const processFile = (file: File) => {
    const reader = new FileReader();
    reader.onload = () => {
      const base64 = (reader.result as string).split(',')[1];
      onFileSelect(base64, file.name);
    };
    reader.readAsDataURL(file);
  };

  return (
    <div className="max-w-2xl mx-auto">
      <div 
        className={`relative border-2 border-dashed rounded-3xl p-12 text-center transition-all ${
          isDragging ? 'border-indigo-500 bg-indigo-50' : 'border-slate-300 bg-white'
        } ${isLoading ? 'opacity-50 pointer-events-none' : 'hover:border-indigo-400'}`}
        onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
        onDragLeave={() => setIsDragging(false)}
        onDrop={(e) => {
          e.preventDefault();
          setIsDragging(false);
          const file = e.dataTransfer.files[0];
          if (file?.type === 'application/pdf') processFile(file);
        }}
      >
        <div className="mb-6">
          <div className="w-20 h-20 bg-indigo-100 text-indigo-600 rounded-full flex items-center justify-center mx-auto mb-4">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
            </svg>
          </div>
          <h3 className="text-2xl font-bold text-slate-800 mb-2">Upload Syllabus or Study Material</h3>
          <p className="text-slate-500 mb-8">PDF files supported. AI will generate questions automatically.</p>
        </div>

        <label className="bg-indigo-600 text-white px-8 py-3 rounded-xl font-semibold cursor-pointer hover:bg-indigo-700 transition-all shadow-lg inline-block">
          Select PDF File
          <input type="file" className="hidden" accept=".pdf" onChange={handleFileChange} />
        </label>

        <p className="mt-4 text-xs text-slate-400">Maximum file size: 10MB</p>
      </div>

      <div className="mt-12 grid grid-cols-1 md:grid-cols-3 gap-6">
        {[
          { title: "Smart Generation", desc: "Advanced AI extracts key concepts accurately." },
          { title: "Timed Practice", desc: "Real exam simulation with configurable timers." },
          { title: "Deep Analysis", desc: "Identify weak areas with topical performance data." }
        ].map((feat, i) => (
          <div key={i} className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
            <h4 className="font-bold text-slate-800 mb-2">{feat.title}</h4>
            <p className="text-slate-500 text-sm leading-relaxed">{feat.desc}</p>
          </div>
        ))}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { Question } from '../types';

interface TestInterfaceProps {
  questions: Question[];
  durationMinutes: number;
  onComplete: (answers: Record<string, number>, timeSpent: number, anomalies: number) => void;
}

export const TestInterface: React.FC<TestInterfaceProps> = ({ 
  questions, 
  durationMinutes, 
  onComplete 
}) => {
  const [currentIdx, setCurrentIdx] = useState(0);
  const [answers, setAnswers] = useState<Record<string, number>>({});
  const [timeLeft, setTimeLeft] = useState(durationMinutes * 60);
  const [anomalies, setAnomalies] = useState(0);
  const [isFocusLost, setIsFocusLost] = useState(false);

  // Auto-detection: Focus monitoring
  useEffect(() => {
    const handleBlur = () => {
      setIsFocusLost(true);
      setAnomalies(prev => prev + 1);
    };
    const handleFocus = () => {
      setIsFocusLost(false);
    };

    window.addEventListener('blur', handleBlur);
    window.addEventListener('focus', handleFocus);
    return () => {
      window.removeEventListener('blur', handleBlur);
      window.removeEventListener('focus', handleFocus);
    };
  }, []);

  // Timer
  useEffect(() => {
    if (timeLeft <= 0) {
      onComplete(answers, durationMinutes * 60, anomalies);
      return;
    }
    const timer = setInterval(() => setTimeLeft(prev => prev - 1), 1000);
    return () => clearInterval(timer);
  }, [timeLeft, answers, onComplete, durationMinutes, anomalies]);

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m}:${s.toString().padStart(2, '0')}`;
  };

  const handleSelect = (optionIdx: number) => {
    setAnswers({ ...answers, [questions[currentIdx].id]: optionIdx });
  };

  const currentQuestion = questions[currentIdx];
  const progress = ((currentIdx + 1) / questions.length) * 100;

  return (
    <div className="max-w-4xl mx-auto">
      {/* Test Header */}
      <div className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4">
        <div className="flex items-center gap-4">
          <div className={`px-4 py-2 rounded-full font-mono text-xl font-bold ${
            timeLeft < 60 ? 'bg-red-100 text-red-600 animate-pulse' : 'bg-slate-100 text-slate-700'
          }`}>
            ⏱️ {formatTime(timeLeft)}
          </div>
          <div className="text-slate-500 font-medium">
            Question {currentIdx + 1} of {questions.length}
          </div>
        </div>

        {isFocusLost && (
          <div className="bg-amber-100 text-amber-700 px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2 border border-amber-200">
            ⚠️ Warning: Focus lost! Don't leave the test window.
          </div>
        )}

        <button 
          onClick={() => onComplete(answers, (durationMinutes * 60) - timeLeft, anomalies)}
          className="bg-slate-800 text-white px-6 py-2 rounded-lg font-bold hover:bg-slate-900 transition-all"
        >
          Submit Test
        </button>
      </div>

      {/* Progress Bar */}
      <div className="w-full h-2 bg-slate-200 rounded-full mb-12 overflow-hidden">
        <div 
          className="h-full bg-indigo-500 transition-all duration-300" 
          style={{ width: `${progress}%` }} 
        />
      </div>

      {/* Question Card */}
      <div className="bg-white rounded-3xl p-8 md:p-12 shadow-xl border border-slate-100 min-h-[400px] flex flex-col justify-between">
        <div>
          <div className="flex items-center gap-2 mb-6">
            <span className="px-3 py-1 bg-indigo-50 text-indigo-600 text-xs font-bold rounded-full uppercase tracking-wider">
              {currentQuestion.category}
            </span>
            <span className={`px-3 py-1 text-xs font-bold rounded-full uppercase tracking-wider ${
              currentQuestion.difficulty === 'Easy' ? 'bg-green-50 text-green-600' :
              currentQuestion.difficulty === 'Medium' ? 'bg-amber-50 text-amber-600' :
              'bg-red-50 text-red-600'
            }`}>
              {currentQuestion.difficulty}
            </span>
          </div>

          <h2 className="text-2xl font-bold text-slate-800 leading-tight mb-8">
            {currentQuestion.question}
          </h2>

          <div className="space-y-4">
            {currentQuestion.options.map((option, idx) => (
              <button
                key={idx}
                onClick={() => handleSelect(idx)}
                className={`w-full p-5 text-left rounded-2xl border-2 transition-all flex items-center gap-4 group ${
                  answers[currentQuestion.id] === idx 
                    ? 'border-indigo-600 bg-indigo-50 shadow-md' 
                    : 'border-slate-100 bg-slate-50 hover:border-indigo-200 hover:bg-white'
                }`}
              >
                <div className={`w-8 h-8 rounded-full flex items-center justify-center font-bold text-sm transition-colors ${
                  answers[currentQuestion.id] === idx 
                    ? 'bg-indigo-600 text-white' 
                    : 'bg-white border border-slate-200 text-slate-500 group-hover:border-indigo-400 group-hover:text-indigo-600'
                }`}>
                  {String.fromCharCode(65 + idx)}
                </div>
                <span className={`font-medium ${
                  answers[currentQuestion.id] === idx ? 'text-indigo-900' : 'text-slate-700'
                }`}>
                  {option}
                </span>
              </button>
            ))}
          </div>
        </div>

        <div className="flex justify-between mt-12 pt-8 border-t border-slate-100">
          <button
            disabled={currentIdx === 0}
            onClick={() => setCurrentIdx(prev => prev - 1)}
            className="px-6 py-2 font-bold text-slate-500 hover:text-indigo-600 disabled:opacity-30 disabled:pointer-events-none transition-colors"
          >
            ← Previous
          </button>
          <button
            onClick={() => {
              if (currentIdx < questions.length - 1) {
                setCurrentIdx(prev => prev + 1);
              } else {
                // Last question
              }
            }}
            className="bg-slate-100 text-slate-700 px-8 py-3 rounded-xl font-bold hover:bg-slate-200 transition-all flex items-center gap-2"
          >
            {currentIdx === questions.length - 1 ? 'Last Question' : 'Next Question →'}
          </button>
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { Radar, RadarChart, PolarGrid, PolarAngleAxis, ResponsiveContainer } from 'recharts';
import { TestResult, Question } from '../types';

interface ResultAnalyticsProps {
  result: TestResult;
  questions: Question[];
  onRestart: () => void;
}

export const ResultAnalytics: React.FC<ResultAnalyticsProps> = ({ result, questions, onRestart }) => {
  const percentage = Math.round((result.score / result.totalQuestions) * 100);

  const radarData = Object.entries(result.categoryBreakdown).map(([subject, data]) => ({
    subject,
    score: Math.round((data.correct / data.total) * 100),
    fullMark: 100
  }));

  const getAccuracyColor = (pct: number) => {
    if (pct >= 80) return 'text-green-500';
    if (pct >= 50) return 'text-amber-500';
    return 'text-red-500';
  };

  return (
    <div className="max-w-5xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">

        {/* Main Score Card */}
        <div className="md:col-span-2 bg-white rounded-3xl p-8 shadow-xl border border-slate-100 flex flex-col items-center justify-center relative overflow-hidden">
          <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-50 rounded-full -mr-16 -mt-16 opacity-50" />
          <h2 className="text-xl font-bold text-slate-400 uppercase tracking-widest mb-4">Overall Score</h2>
          <div className="relative">
             <svg className="w-48 h-48 transform -rotate-90">
                <circle cx="96" cy="96" r="88" stroke="currentColor" strokeWidth="12" fill="transparent" className="text-slate-100" />
                <circle 
                  cx="96" cy="96" r="88" stroke="currentColor" strokeWidth="12" fill="transparent" 
                  strokeDasharray={2 * Math.PI * 88}
                  strokeDashoffset={2 * Math.PI * 88 * (1 - percentage / 100)}
                  className={`${getAccuracyColor(percentage)} transition-all duration-1000 ease-out`} 
                />
             </svg>
             <div className="absolute inset-0 flex flex-col items-center justify-center">
                <span className="text-5xl font-black text-slate-800">{percentage}%</span>
                <span className="text-slate-400 font-bold">{result.score} / {result.totalQuestions}</span>
             </div>
          </div>
          <div className="mt-8 grid grid-cols-2 w-full gap-4 text-center">
            <div className="p-4 bg-slate-50 rounded-2xl">
              <p className="text-xs font-bold text-slate-400 uppercase">Time Spent</p>
              <p className="text-xl font-bold text-slate-800">
                {Math.floor(result.timeSpent / 60)}m {result.timeSpent % 60}s
              </p>
            </div>
            <div className="p-4 bg-slate-50 rounded-2xl">
              <p className="text-xs font-bold text-slate-400 uppercase">Integrity Rank</p>
              <p className={`text-xl font-bold ${result.anomalies > 5 ? 'text-red-500' : 'text-green-500'}`}>
                {result.anomalies > 5 ? 'Suspicious' : 'Excellent'}
              </p>
            </div>
          </div>
        </div>

        {/* Radar Analysis */}
        <div className="bg-white rounded-3xl p-8 shadow-xl border border-slate-100 flex flex-col">
          <h3 className="text-lg font-bold text-slate-800 mb-6">Strengths & Weaknesses</h3>
          <div className="h-[250px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <RadarChart cx="50%" cy="50%" outerRadius="80%" data={radarData}>
                <PolarGrid stroke="#e2e8f0" />
                <PolarAngleAxis dataKey="subject" tick={{ fill: '#64748b', fontSize: 10 }} />
                <Radar
                  name="Score"
                  dataKey="score"
                  stroke="#4f46e5"
                  fill="#4f46e5"
                  fillOpacity={0.5}
                />
              </RadarChart>
            </ResponsiveContainer>
          </div>
          <div className="mt-auto space-y-2">
            {Object.entries(result.categoryBreakdown).map(([cat, data]) => (
              <div key={cat} className="flex justify-between items-center text-sm">
                <span className="text-slate-600 font-medium">{cat}</span>
                <span className="text-slate-400 font-bold">{Math.round((data.correct/data.total)*100)}%</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Review Section */}
      <div className="bg-white rounded-3xl p-8 shadow-xl border border-slate-100">
        <h3 className="text-xl font-bold text-slate-800 mb-8">Detailed Review</h3>
        <div className="space-y-6">
          {questions.map((q, idx) => {
            const userAnswerIdx = result.answers[q.id];
            const isCorrect = userAnswerIdx === q.correctAnswer;
            return (
              <div key={q.id} className={`p-6 rounded-2xl border-2 ${isCorrect ? 'border-green-100 bg-green-50/30' : 'border-red-100 bg-red-50/30'}`}>
                <div className="flex gap-4">
                  <span className={`w-8 h-8 rounded-full flex items-center justify-center font-bold text-sm shrink-0 ${isCorrect ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
                    {idx + 1}
                  </span>
                  <div>
                    <p className="font-bold text-slate-800 mb-4">{q.question}</p>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-3 mb-4">
                      {q.options.map((opt, oIdx) => (
                        <div key={oIdx} className={`px-4 py-2 rounded-lg text-sm flex items-center justify-between ${
                          oIdx === q.correctAnswer ? 'bg-green-100 text-green-800 font-bold' :
                          oIdx === userAnswerIdx ? 'bg-red-100 text-red-800 font-bold' :
                          'bg-white text-slate-500 border border-slate-200'
                        }`}>
                          <span>{opt}</span>
                          {oIdx === q.correctAnswer && <span>✓</span>}
                          {oIdx === userAnswerIdx && !isCorrect && <span>✗</span>}
                        </div>
                      ))}
                    </div>
                    <div className="bg-white/50 p-4 rounded-xl border border-slate-200/50">
                      <p className="text-xs font-bold text-indigo-600 uppercase mb-1">AI Explanation</p>
                      <p className="text-sm text-slate-600 italic">"{q.explanation}"</p>
                    </div>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      </div>

      <div className="flex justify-center pb-12">
        <button 
          onClick={onRestart}
          className="bg-indigo-600 text-white px-12 py-4 rounded-2xl font-bold text-lg hover:bg-indigo-700 transition-all shadow-xl hover:-translate-y-1 active:translate-y-0"
        >
          Take Another Test
        </button>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { FileUpload } from './components/FileUpload';
import { TestInterface } from './components/TestInterface';
import { ResultAnalytics } from './components/ResultAnalytics';
import { generateMockTestFromContent } from './services/geminiService';
import { AppState, Question, TestResult, TestConfig } from './types';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.IDLE);
  const [questions, setQuestions] = useState<Question[]>([]);
  const [result, setResult] = useState<TestResult | null>(null);
  const [config, setConfig] = useState<TestConfig>({
    title: 'Generated Mock Test',
    duration: 15,
    questionCount: 10
  });

  const handleFileUpload = async (base64: string, fileName: string) => {
    setAppState(AppState.GENERATING);
    try {
      const generatedQuestions = await generateMockTestFromContent(base64, config.questionCount);
      setQuestions(generatedQuestions);
      setConfig(prev => ({ ...prev, title: fileName.replace('.pdf', '') }));
      setAppState(AppState.TESTING);
    } catch (err) {
      alert("Failed to generate test. Please try another PDF.");
      setAppState(AppState.IDLE);
    }
  };

  const calculateResults = (
    answers: Record<string, number>, 
    timeSpent: number, 
    anomalies: number
  ) => {
    let score = 0;
    const categoryMap: Record<string, { correct: number; total: number }> = {};

    questions.forEach(q => {
      if (!categoryMap[q.category]) {
        categoryMap[q.category] = { correct: 0, total: 0 };
      }
      categoryMap[q.category].total++;

      if (answers[q.id] === q.correctAnswer) {
        score++;
        categoryMap[q.category].correct++;
      }
    });

    const finalResult: TestResult = {
      score,
      totalQuestions: questions.length,
      timeSpent,
      answers,
      timestamp: Date.now(),
      anomalies,
      categoryBreakdown: categoryMap
    };

    setResult(finalResult);
    setAppState(AppState.COMPLETED);
  };

  const restart = () => {
    setAppState(AppState.IDLE);
    setQuestions([]);
    setResult(null);
  };

  return (
    <Layout>
      {appState === AppState.IDLE && (
        <div className="animate-in fade-in zoom-in duration-500">
          <div className="text-center mb-16 max-w-3xl mx-auto">
            <h1 className="text-4xl md:text-6xl font-black text-slate-800 mb-6 leading-tight">
              Turn your Study Notes into <span className="text-indigo-600">Smart Mock Tests</span>
            </h1>
            <p className="text-xl text-slate-500 leading-relaxed">
              Upload any PDF textbook, lecture slide, or notes and let our AI create a professional examination for you in seconds.
            </p>
          </div>

          <div className="flex flex-col md:flex-row gap-6 justify-center mb-12">
             <div className="flex items-center gap-2 bg-white px-4 py-2 rounded-xl shadow-sm border border-slate-100">
                <span className="text-slate-400 font-bold uppercase text-[10px] tracking-widest">Question Count</span>
                <select 
                  className="bg-transparent font-bold text-slate-700 outline-none"
                  value={config.questionCount}
                  onChange={(e) => setConfig({...config, questionCount: parseInt(e.target.value)})}
                >
                  <option value={5}>5 Questions</option>
                  <option value={10}>10 Questions</option>
                  <option value={20}>20 Questions</option>
                </select>
             </div>
             <div className="flex items-center gap-2 bg-white px-4 py-2 rounded-xl shadow-sm border border-slate-100">
                <span className="text-slate-400 font-bold uppercase text-[10px] tracking-widest">Time Limit</span>
                <select 
                   className="bg-transparent font-bold text-slate-700 outline-none"
                   value={config.duration}
                   onChange={(e) => setConfig({...config, duration: parseInt(e.target.value)})}
                >
                  <option value={5}>5 Minutes</option>
                  <option value={15}>15 Minutes</option>
                  <option value={30}>30 Minutes</option>
                  <option value={60}>1 Hour</option>
                </select>
             </div>
          </div>

          <FileUpload onFileSelect={handleFileUpload} isLoading={false} />
        </div>
      )}

      {appState === AppState.GENERATING && (
        <div className="flex flex-col items-center justify-center min-h-[60vh] text-center space-y-8 animate-pulse">
          <div className="relative">
             <div className="w-24 h-24 border-8 border-indigo-100 border-t-indigo-600 rounded-full animate-spin"></div>
             <div className="absolute inset-0 flex items-center justify-center font-bold text-indigo-600">AI</div>
          </div>
          <div>
            <h2 className="text-2xl font-bold text-slate-800 mb-2">Analyzing your PDF...</h2>
            <p className="text-slate-500">Extracting concepts and drafting questions. This usually takes 10-15 seconds.</p>
          </div>
          <div className="max-w-md w-full bg-slate-100 h-2 rounded-full overflow-hidden">
             <div className="bg-indigo-600 h-full w-1/2 animate-bounce"></div>
          </div>
        </div>
      )}

      {appState === AppState.TESTING && (
        <TestInterface 
          questions={questions} 
          durationMinutes={config.duration} 
          onComplete={calculateResults}
        />
      )}

      {appState === AppState.COMPLETED && result && (
        <ResultAnalytics 
          result={result} 
          questions={questions} 
          onRestart={restart} 
        />
      )}
    </Layout>
  );
};

