          </div>
          <div className="max-w-sm w-full bg-slate-100 h-3 rounded-full overflow-hidden shadow-inner">
             <div className="bg-gradient-to-r from-indigo-600 to-violet-600 h-full w-[60%] animate-[shimmer_2s_infinite]"></div>
          </div>
        </div>
      )}

      {appState === AppState.TESTING && (
        <TestInterface 
          questions={questions} 
          durationMinutes={config.duration} 
          onComplete={calculateResults}
        />
      )}

      {appState === AppState.COMPLETED && result && (
        <ResultAnalytics 
          result={result} 
          questions={questions} 
          onRestart={restart} 
        />
      )}
    </Layout>
  );
};

export default App;

export interface Question {
  id: string;
  question: string;
  options: string[];
  correctAnswer: number;
  explanation: string;
  category: string;
  difficulty: 'Easy' | 'Medium' | 'Hard';
  hint?: string;
}

export interface TestResult {
  score: number;
  totalQuestions: number;
  timeSpent: number; // in seconds
  answers: Record<string, number>;
  timestamp: number;
  anomalies: number; // For "auto-detection" focus loss
  categoryBreakdown: Record<string, { correct: number; total: number }>;
}

export enum AppState {
  IDLE = 'IDLE',
  ABOUT = 'ABOUT',
  CONFIGURING = 'CONFIGURING',
  UPLOADING = 'UPLOADING',
  GENERATING = 'GENERATING',
  TESTING = 'TESTING',
  COMPLETED = 'COMPLETED'
}

export interface TestConfig {
  title: string;
  duration: number; // in minutes
  questionCount: number;
  topics: string; // Specific topics to focus on
}

