            <button 
              onClick={() => setShowAuthModal(null)}
              className="absolute top-6 right-6 text-slate-400 hover:text-slate-600 transition-colors"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>
            <div className="text-center mb-8">
               <h3 className="text-3xl font-black text-slate-800 mb-2">
                 {showAuthModal === 'signin' ? 'Welcome Back' : 'Join ExamAI'}
               </h3>
               <p className="text-slate-500 font-medium">Please enter your details to continue.</p>
            </div>
            <div className="space-y-4">
               {authError && (
                 <div className="bg-red-50 text-red-600 text-xs font-bold p-4 rounded-xl border border-red-100">
                   {authError}
                 </div>
               )}
               <input 
                 type="email" 
                 placeholder="Email Address" 
                 value={authData.email}
                 onChange={(e) => setAuthData({...authData, email: e.target.value})}
                 className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl px-6 py-4 outline-none focus:border-indigo-500 transition-all" 
               />
               <input 
                 type="password" 
                 placeholder="Password" 
                 value={authData.password}
                 onChange={(e) => setAuthData({...authData, password: e.target.value})}
                 className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl px-6 py-4 outline-none focus:border-indigo-500 transition-all" 
               />
               <button 
                 disabled={authLoading}
                 onClick={handleAuthAction}
                 className="w-full bg-indigo-600 text-white py-4 rounded-2xl font-bold text-lg hover:bg-indigo-700 transition-all shadow-xl flex items-center justify-center disabled:opacity-50"
               >
                 {authLoading ? (
                   <div className="w-6 h-6 border-4 border-white border-t-transparent rounded-full animate-spin"></div>
                 ) : (
                   showAuthModal === 'signin' ? 'Sign In' : 'Create Account'
                 )}
               </button>
               <div className="text-center pt-2">
                 <button 
                   onClick={() => setShowAuthModal(showAuthModal === 'signin' ? 'signup' : 'signin')}
